const TerminalConsole: React.FC = () => {
  const [seqIdx, setSeqIdx] = useState(0)
  const [lines, setLines] = useState<{ text: string; type: string }[]>([])
  const [phase, setPhase] = useState<"typing" | "pause">("typing")

  useEffect(() => {
    const seq = sequences[seqIdx]
    let i = 0
    setLines([])
    setPhase("typing")

    const addNext = () => {
      if (i < seq.lines.length) {
        const line = seq.lines[i]
        setLines(prev => [...prev, line])
        i++
        const delay = line.type === "cmd" ? 1200 : line.type === "blank" ? 400 : 600
        setTimeout(addNext, delay)
      } else {
        setPhase("pause")
        setTimeout(() => {
          setSeqIdx(prev => (prev + 1) % sequences.length)
        }, 4000)
      }
    }

    const kickoff = setTimeout(addNext, 800)
    return () => clearTimeout(kickoff)
  }, [seqIdx])

  const seq = sequences[seqIdx]

  return (
    <div className="terminal-console">
      <div className="terminal-header">
        <div className="terminal-dots">
          <span className="dot red"></span>
          <span className="dot yellow"></span>
          <span className="dot green"></span>
        </div>
        <span className="terminal-title">
          {seq.title} — guest@sec.antonio.sh
        </span>
      </div>
      <div className="terminal-body mono">
        {lines.map((line, i) => {
          if (line.type === "blank") return <div key={i} className="terminal-line blank">&nbsp;</div>
          const prefix = line.type === "cmd" ? "❯ " : "  "
          return (
            <div key={i} className={`terminal-line ${line.type}`}>
              {prefix}{line.text}
            </div>
          )
        })}
        {phase === "typing" && (
          <div className="terminal-cursor-line">
            <span>{"❯"}</span> <span className="typing-cursor"></span>
          </div>
        )}
      </div>
    </div>
  )
}

